// Bring both ensures conjuncts into the proof context under their shared
// right-hand side so z3 can unify `post1_self_@` and `post2_self_@` via the
// common `pre_self_@.insert(key@, value)` expression.
if (post1_self_@ == pre_self_@.insert(key@, value))
    && (post2_self_@ == pre_self_@.insert(key@, value)) {
    // Transitivity through the shared insert expression.
    assert(post1_self_@ == post2_self_@);
    // Extensional Map equality, in case det_insert_equal expects `=~=`.
    assert(post1_self_@ =~= post2_self_@);
    // Both returns are `()`, so they are trivially equal.
    assert(r1 == r2);
}
